import{_ as e,c as i,o as t,V as l}from"./chunks/framework.yB9ribBw.js";const f=JSON.parse('{"title":"vue性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"guide/interview/vue/vue/vue性能优化.md","filePath":"guide/interview/vue/vue/vue性能优化.md","lastUpdated":1719242077000}'),a={name:"guide/interview/vue/vue/vue性能优化.md"},_=l('<h1 id="vue性能优化" tabindex="-1">vue性能优化 <a class="header-anchor" href="#vue性能优化" aria-label="Permalink to &quot;vue性能优化&quot;">​</a></h1><ul><li>对象层级不要过深，否则性能就会差</li><li>不需要响应式的数据不要放到 data 中（可以用 Object.freeze() 冻结数据）</li><li>v-if 和 v-show 区分使用场景</li><li>computed 和 watch 区分使用场景</li><li>v-for 遍历必须加 key，key 最好是 id 值，且避免同时使用 v-if</li><li>大数据列表和表格性能优化-虚拟列表/虚拟表格</li><li>防止内部泄漏，组件销毁后把全局变量和事件销毁</li><li>图片懒加载</li><li>路由懒加载</li><li>第三方插件的按需引入</li><li>适当采用 keep-alive 缓存组件</li><li>防抖、节流运用</li><li>服务端渲染 SSR or 预渲染</li></ul>',2),o=[_];function r(u,s,v,c,d,n){return t(),i("div",null,o)}const h=e(a,[["render",r]]);export{f as __pageData,h as default};
